// Decode base64 PDF
const pdfBase64 = $input.first().json.pdf_base64;
const pdfBuffer = Buffer.from(pdfBase64, 'base64');

// Prepare email data
const invoice = $input.first().json.invoice;
const client = $input.first().json.client;
const seller = $input.first().json.seller;
const payment = $input.first().json.payment;

// Format items for email body
let itemsList = '';
if (invoice.items && invoice.items.length > 0) {
  itemsList = invoice.items.map(item => 
    `- ${item.description}: ${item.quantity} x ${item.total.toFixed(2)} €`
  ).join('\n');
}

// Build email body
const emailBody = `Bonjour ${client.name},

Veuillez trouver ci-joint votre facture ${invoice.number}.

Détails :
- Date d'émission : ${invoice.date}
- Date d'échéance : ${invoice.due_date}
- Montant total : ${invoice.total.toFixed(2)} ${invoice.currency}

${itemsList ? 'Prestations :\n' + itemsList + '\n\n' : ''}${payment.bank_iban ? 'Coordonnées bancaires :\nIBAN : ' + payment.bank_iban + (payment.bank_bic ? '\nBIC : ' + payment.bank_bic : '') + '\n\n' : ''}${invoice.notes ? 'Notes : ' + invoice.notes + '\n\n' : ''}Cordialement,
${seller.company || seller.name}
${seller.phone ? 'Tél : ' + seller.phone : ''}
${seller.email}`;

return {
  json: {
    to: client.email,
    subject: `Facture ${invoice.number} - ${seller.company || seller.name}`,
    body: emailBody,
    invoiceNumber: invoice.number,
    sellerEmail: seller.email
  },
  binary: {
    attachment: {
      data: pdfBase64,
      mimeType: 'application/pdf',
      fileName: `${invoice.number}.pdf`
    }
  }
};
